// The synthetic ensures has the shape `H ==> det_<f>_equal(...)`, where H is
// the big conjunction of the two original-call ensures (one for `post1_self_`
// and one for `post2_self_`). Because H is the *antecedent* of an implication,
// none of its conjuncts are available as body-level hypotheses on entry —
// they only enter the SMT context when Verus discharges the ensures at
// function exit. That is why the previous attempt's unconditional
// `assert(forall|p| ... ==> post1_self_@[p as int] =~= pre_self_@[p as int])`
// failed: there was no path through the body on which the post1 ensures was
// known.
//
// The fix is to wrap the proof inside `if H_relevant { ... }`. Anything we
// assert inside the branch is recorded by Verus as
// `H_relevant ==> assertion`, which is exactly the form needed to discharge
// the synthetic ensures at exit (since H trivially implies H_relevant).
//
// Inside the branch we have the per-run conjuncts of H as a path condition.
// We use them to prove `post1_self_@ =~= post2_self_@` via the standard
// "pointwise + `=~=`" pattern, splitting on whether the index is `ioid`
// (where every observable Option<PageTable> field of post* is pinned the
// same way for both runs via `pre_self_`) or not (where each forall ensures
// collapses `post*_self_@[p]` to `pre_self_@[p]`).
if pre_self_.wf()
    && post1_self_.wf()
    && post2_self_.wf()
    && (forall|p: IOid|
            #![trigger post1_self_@[p as int]]
            #![trigger pre_self_@[p as int]]
            0 <= p < IOID_MAX && p != ioid ==>
                post1_self_@[p as int] =~= pre_self_@[p as int])
    && (forall|p: IOid|
            #![trigger post2_self_@[p as int]]
            #![trigger pre_self_@[p as int]]
            0 <= p < IOID_MAX && p != ioid ==>
                post2_self_@[p as int] =~= pre_self_@[p as int])
    && post1_self_@[ioid as int].is_Some()
    && post2_self_@[ioid as int].is_Some()
    && post1_self_@[ioid as int].unwrap().wf()
    && post2_self_@[ioid as int].unwrap().wf()
    && post1_self_@[ioid as int].unwrap().ioid
        == pre_self_@[ioid as int].unwrap().ioid
    && post2_self_@[ioid as int].unwrap().ioid
        == pre_self_@[ioid as int].unwrap().ioid
    && post1_self_@[ioid as int].unwrap().kernel_l4_end
        == pre_self_@[ioid as int].unwrap().kernel_l4_end
    && post2_self_@[ioid as int].unwrap().kernel_l4_end
        == pre_self_@[ioid as int].unwrap().kernel_l4_end
    && post1_self_@[ioid as int].unwrap().page_closure()
        =~= pre_self_@[ioid as int].unwrap().page_closure().insert(page_map_ptr)
    && post2_self_@[ioid as int].unwrap().page_closure()
        =~= pre_self_@[ioid as int].unwrap().page_closure().insert(page_map_ptr)
    && post1_self_@[ioid as int].unwrap().mapping_4k()
        =~= pre_self_@[ioid as int].unwrap().mapping_4k()
    && post2_self_@[ioid as int].unwrap().mapping_4k()
        =~= pre_self_@[ioid as int].unwrap().mapping_4k()
    && post1_self_@[ioid as int].unwrap().mapping_2m()
        =~= pre_self_@[ioid as int].unwrap().mapping_2m()
    && post2_self_@[ioid as int].unwrap().mapping_2m()
        =~= pre_self_@[ioid as int].unwrap().mapping_2m()
    && post1_self_@[ioid as int].unwrap().mapping_1g()
        =~= pre_self_@[ioid as int].unwrap().mapping_1g()
    && post2_self_@[ioid as int].unwrap().mapping_1g()
        =~= pre_self_@[ioid as int].unwrap().mapping_1g()
    && post1_self_@[ioid as int].unwrap().spec_resolve_mapping_l4(target_l4i).is_Some()
    && post2_self_@[ioid as int].unwrap().spec_resolve_mapping_l4(target_l4i).is_Some()
    && post1_self_@[ioid as int].unwrap().spec_resolve_mapping_l4(target_l4i).get_Some_0().addr
        == page_map_ptr
    && post2_self_@[ioid as int].unwrap().spec_resolve_mapping_l4(target_l4i).get_Some_0().addr
        == page_map_ptr
    && post1_self_@[ioid as int].unwrap().kernel_entries
        =~= pre_self_@[ioid as int].unwrap().kernel_entries
    && post2_self_@[ioid as int].unwrap().kernel_entries
        =~= pre_self_@[ioid as int].unwrap().kernel_entries
{
    // Lengths agree — both Arrays are wf, so .seq@ has length PCID_MAX.
    assert(post1_self_@.len() == PCID_MAX as int);
    assert(post2_self_@.len() == PCID_MAX as int);

    // Pointwise equality of the two Array views, split on whether the index
    // is the modified one (`ioid`) or not. Phrasing the case-split bound
    // variable uniformly as `p` keeps the same Seq-index term that the
    // foralls were stated with.
    assert forall|p: int| 0 <= p < IOID_MAX implies
        post1_self_@[p] =~= post2_self_@[p] by {
        if p == ioid as int {
            // Both `post1_self_@[ioid]` and `post2_self_@[ioid]` are Some,
            // and every observable field of their inner PageTable is pinned
            // by the ensures of each run to a value that matches the other
            // run's (going through `pre_self_@[ioid]` as the common
            // reference point).
            assert(post1_self_@[p].is_Some());
            assert(post2_self_@[p].is_Some());

            // .ioid (pre.ioid == pre.ioid by reflexivity)
            assert(post1_self_@[p].unwrap().ioid
                == pre_self_@[ioid as int].unwrap().ioid);
            assert(post2_self_@[p].unwrap().ioid
                == pre_self_@[ioid as int].unwrap().ioid);
            assert(post1_self_@[p].unwrap().ioid
                == post2_self_@[p].unwrap().ioid);

            // .kernel_l4_end
            assert(post1_self_@[p].unwrap().kernel_l4_end
                == pre_self_@[ioid as int].unwrap().kernel_l4_end);
            assert(post2_self_@[p].unwrap().kernel_l4_end
                == pre_self_@[ioid as int].unwrap().kernel_l4_end);
            assert(post1_self_@[p].unwrap().kernel_l4_end
                == post2_self_@[p].unwrap().kernel_l4_end);

            // .page_closure() — both equal pre.page_closure().insert(page_map_ptr)
            assert(post1_self_@[p].unwrap().page_closure()
                =~= pre_self_@[ioid as int].unwrap().page_closure().insert(page_map_ptr));
            assert(post2_self_@[p].unwrap().page_closure()
                =~= pre_self_@[ioid as int].unwrap().page_closure().insert(page_map_ptr));
            assert(post1_self_@[p].unwrap().page_closure()
                =~= post2_self_@[p].unwrap().page_closure());

            // .mapping_4k / .mapping_2m / .mapping_1g — all match pre.
            assert(post1_self_@[p].unwrap().mapping_4k()
                =~= pre_self_@[ioid as int].unwrap().mapping_4k());
            assert(post2_self_@[p].unwrap().mapping_4k()
                =~= pre_self_@[ioid as int].unwrap().mapping_4k());
            assert(post1_self_@[p].unwrap().mapping_4k()
                =~= post2_self_@[p].unwrap().mapping_4k());

            assert(post1_self_@[p].unwrap().mapping_2m()
                =~= pre_self_@[ioid as int].unwrap().mapping_2m());
            assert(post2_self_@[p].unwrap().mapping_2m()
                =~= pre_self_@[ioid as int].unwrap().mapping_2m());
            assert(post1_self_@[p].unwrap().mapping_2m()
                =~= post2_self_@[p].unwrap().mapping_2m());

            assert(post1_self_@[p].unwrap().mapping_1g()
                =~= pre_self_@[ioid as int].unwrap().mapping_1g());
            assert(post2_self_@[p].unwrap().mapping_1g()
                =~= pre_self_@[ioid as int].unwrap().mapping_1g());
            assert(post1_self_@[p].unwrap().mapping_1g()
                =~= post2_self_@[p].unwrap().mapping_1g());

            // .spec_resolve_mapping_l4(target_l4i) — both Some with .addr == page_map_ptr.
            assert(post1_self_@[p].unwrap().spec_resolve_mapping_l4(target_l4i).is_Some());
            assert(post2_self_@[p].unwrap().spec_resolve_mapping_l4(target_l4i).is_Some());
            assert(post1_self_@[p].unwrap().spec_resolve_mapping_l4(target_l4i).get_Some_0().addr
                == page_map_ptr);
            assert(post2_self_@[p].unwrap().spec_resolve_mapping_l4(target_l4i).get_Some_0().addr
                == page_map_ptr);

            // .kernel_entries
            assert(post1_self_@[p].unwrap().kernel_entries
                =~= pre_self_@[ioid as int].unwrap().kernel_entries);
            assert(post2_self_@[p].unwrap().kernel_entries
                =~= pre_self_@[ioid as int].unwrap().kernel_entries);
            assert(post1_self_@[p].unwrap().kernel_entries
                =~= post2_self_@[p].unwrap().kernel_entries);
        } else {
            // For p != ioid, each per-run forall pins post*_self_@[p] to
            // pre_self_@[p]. Mentioning both indexed views here fires both
            // foralls at the same `p`.
            assert(post1_self_@[p as int] =~= pre_self_@[p as int]);
            assert(post2_self_@[p as int] =~= pre_self_@[p as int]);
        }
    }

    // Lift the pointwise equality to Seq extensional equality of the views.
    assert(post1_self_@ =~= post2_self_@);
}

// r1 and r2 are both unit, so trivially equal — this assertion is body-level
// (and `()` equality is definitional, so it needs no hypothesis from H).
assert(r1 == r2);
